const now = new Date();
const period = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
return [{
  json: {
    configFile: '/workspace/billing-workbook/docs/looker-summary-only.json',
    period,
    billingApiBaseUrl: 'http://host.docker.internal:4174',
    billingApiToken: '',
    lookerClientId: '',
    lookerClientSecret: ''
  }
}];

const q = (value) => `"${String(value ?? '').replace(/(["\\$`])/g, '\\$1')}"`;
const cmd = [
  'python3',
  q('/workspace/billing-workbook/tools/pull_looker_and_push.py'),
  '--config-file',
  q($json.configFile),
  '--period',
  q($json.period),
  '--billing-api-base-url',
  q($json.billingApiBaseUrl)
];
if ($json.billingApiToken) {
  cmd.push('--billing-api-token', q($json.billingApiToken));
}
if ($json.lookerClientId) {
  cmd.push('--looker-client-id', q($json.lookerClientId));
}
if ($json.lookerClientSecret) {
  cmd.push('--looker-client-secret', q($json.lookerClientSecret));
}
return [{ json: { ...$json, command: cmd.join(' ') } }];

const raw = $json.stdout || '{}';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error(`Could not parse summary import output as JSON. stdout: ${raw}`);
}
return [{ json: parsed }];
